document.addEventListener(`DOMContentLoaded`,()=>{let e=document.querySelector(`.burger-menu`),t=document.querySelector(`.burger-menu__btn`),n=t.querySelector(`.open`),r=t.querySelector(`.close`),i={isActive:`is-active`,isLock:`is-lock`,visuallyHidden:`visually-hidden`};t.addEventListener(`click`,()=>{e.classList.toggle(i.isActive),document.documentElement.classList.toggle(i.isLock),e.classList.contains(i.isActive)?(n.classList.add(i.visuallyHidden),r.classList.remove(i.visuallyHidden)):(n.classList.remove(i.visuallyHidden),r.classList.add(i.visuallyHidden))})});